import React, { useEffect, useMemo, useRef, useState } from 'react';
import './App.css';

type User = {
  id: number;
  name: string;
  email: string;
  role: 'Admin' | 'Editor' | 'Viewer';
};

type SortKey = 'id' | 'name' | 'role';
type SortDirection = 'asc' | 'desc';

const USERS: User[] = [
  { id: 1, name: 'Alice Johnson', email: 'alice@example.com', role: 'Admin' },
  { id: 2, name: 'Bob Smith', email: 'bob@example.com', role: 'Editor' },
  { id: 3, name: 'Carla Perez', email: 'carla@example.com', role: 'Viewer' },
  { id: 4, name: 'David Kim', email: 'david@example.com', role: 'Editor' },
  { id: 5, name: 'Emma Brown', email: 'emma@example.com', role: 'Viewer' },
  { id: 6, name: 'Frank Wu', email: 'frank@example.com', role: 'Admin' },
  { id: 7, name: 'Grace Lee', email: 'grace@example.com', role: 'Viewer' },
  { id: 8, name: 'Henry Ford', email: 'henry@example.com', role: 'Editor' },
  { id: 9, name: 'Ivy Stone', email: 'ivy@example.com', role: 'Viewer' },
  { id: 10, name: 'Jack Ryan', email: 'jack@example.com', role: 'Viewer' },
  { id: 11, name: 'Karen Diaz', email: 'karen@example.com', role: 'Editor' },
  { id: 12, name: 'Leo Walker', email: 'leo@example.com', role: 'Viewer' },
  { id: 13, name: 'Mia Clark', email: 'mia@example.com', role: 'Admin' }
];

const PAGE_SIZES = [5, 10] as const;

function normalize(value: string): string {
  return value.trim().toLowerCase();
}

function filterUsers(query: string): User[] {
  const needle = normalize(query);
  if (!needle) return USERS;

  return USERS.filter((user) =>
    user.name.toLowerCase().includes(needle) ||
    user.email.toLowerCase().includes(needle) ||
    user.role.toLowerCase().includes(needle)
  );
}

function userCountText(count: number, suffix: 'found' | 'selected'): string {
  return count + ' ' + (count === 1 ? 'user' : 'users') + ' ' + suffix + '.';
}

function pageStatus(
  page: number,
  totalPages: number,
  visibleCount: number,
  resultCount: number
): string {
  return (
    'Page ' + page + ' of ' + totalPages + '. Showing ' +
    visibleCount + ' of ' + resultCount + ' users.'
  );
}

export default function App() {
  const [query, setQuery] = useState('');
  const [pageSize, setPageSize] = useState<number>(PAGE_SIZES[0]);
  const [currentPage, setCurrentPage] = useState(1);
  const [sortKey, setSortKey] = useState<SortKey>('id');
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc');
  const [selectedIds, setSelectedIds] = useState<Set<number>>(
    () => new Set<number>()
  );
  const [status, setStatus] = useState(
    'Page 1 of 3. Showing 5 of 13 users.'
  );
  const selectPageRef = useRef<HTMLInputElement | null>(null);

  const filteredUsers = useMemo(() => filterUsers(query), [query]);

  const sortedUsers = useMemo(() => {
    return filteredUsers
      .map((user) => ({
        user,
        sourceIndex: USERS.findIndex((candidate) => candidate.id === user.id)
      }))
      .sort((left, right) => {
        let comparison = 0;

        if (sortKey === 'id') {
          comparison = left.user.id - right.user.id;
        } else {
          comparison = left.user[sortKey].localeCompare(
            right.user[sortKey],
            'en',
            { sensitivity: 'base' }
          );
        }

        if (comparison === 0) {
          return left.sourceIndex - right.sourceIndex;
        }

        return sortDirection === 'asc' ? comparison : -comparison;
      })
      .map((entry) => entry.user);
  }, [filteredUsers, sortDirection, sortKey]);

  const totalPages = Math.max(1, Math.ceil(sortedUsers.length / pageSize));
  const safeCurrentPage = Math.min(currentPage, totalPages);
  const pageStart = (safeCurrentPage - 1) * pageSize;
  const pageUsers = sortedUsers.slice(pageStart, pageStart + pageSize);

  const selectedOnPage = pageUsers.filter((user) =>
    selectedIds.has(user.id)
  ).length;
  const allPageSelected =
    pageUsers.length > 0 && selectedOnPage === pageUsers.length;
  const pageSelectionState: 'false' | 'mixed' | 'true' =
    allPageSelected ? 'true' : selectedOnPage > 0 ? 'mixed' : 'false';

  useEffect(() => {
    if (selectPageRef.current) {
      selectPageRef.current.indeterminate = pageSelectionState === 'mixed';
    }
  }, [pageSelectionState]);

  function resetToFirstPage(): void {
    setCurrentPage(1);
  }

  function handleSearchChange(
    event: React.ChangeEvent<HTMLInputElement>
  ): void {
    const nextQuery = event.target.value;
    const nextResults = filterUsers(nextQuery);
    const nextTotalPages = Math.max(
      1,
      Math.ceil(nextResults.length / pageSize)
    );

    setQuery(nextQuery);
    resetToFirstPage();
    setStatus(
      pageStatus(
        1,
        nextTotalPages,
        Math.min(pageSize, nextResults.length),
        nextResults.length
      )
    );
  }

  function handleSearchKeyDown(
    event: React.KeyboardEvent<HTMLInputElement>
  ): void {
    if (event.key !== 'Escape') return;

    event.preventDefault();
    setQuery('');
    resetToFirstPage();
    setStatus('Search cleared. 13 users found.');
  }

  function handlePageSizeChange(
    event: React.ChangeEvent<HTMLSelectElement>
  ): void {
    const nextPageSize = Number(event.target.value);
    const nextTotalPages = Math.max(
      1,
      Math.ceil(filteredUsers.length / nextPageSize)
    );

    setPageSize(nextPageSize);
    resetToFirstPage();
    setStatus(
      pageStatus(
        1,
        nextTotalPages,
        Math.min(nextPageSize, filteredUsers.length),
        filteredUsers.length
      )
    );
  }

  function handleSort(nextKey: SortKey): void {
    const nextDirection: SortDirection =
      sortKey === nextKey && sortDirection === 'asc' ? 'desc' : 'asc';

    setSortKey(nextKey);
    setSortDirection(nextDirection);
    resetToFirstPage();
    setStatus(
      'Sorted by ' + nextKey.toUpperCase() + ' ' +
      (nextDirection === 'asc' ? 'ascending' : 'descending') + '.'
    );
  }

  function goPrevious(): void {
    if (safeCurrentPage <= 1) return;

    const nextPage = safeCurrentPage - 1;
    const visibleCount = Math.min(
      pageSize,
      Math.max(0, sortedUsers.length - (nextPage - 1) * pageSize)
    );
    setCurrentPage(nextPage);
    setStatus(
      pageStatus(nextPage, totalPages, visibleCount, sortedUsers.length)
    );
  }

  function goNext(): void {
    if (safeCurrentPage >= totalPages) return;

    const nextPage = safeCurrentPage + 1;
    const visibleCount = Math.min(
      pageSize,
      Math.max(0, sortedUsers.length - (nextPage - 1) * pageSize)
    );
    setCurrentPage(nextPage);
    setStatus(
      pageStatus(nextPage, totalPages, visibleCount, sortedUsers.length)
    );
  }

  function toggleUser(user: User): void {
    setSelectedIds((current) => {
      const next = new Set(current);
      if (next.has(user.id)) {
        next.delete(user.id);
        setStatus(
          user.name + ' deselected. ' +
          userCountText(next.size, 'selected')
        );
      } else {
        next.add(user.id);
        setStatus(
          user.name + ' selected. ' +
          userCountText(next.size, 'selected')
        );
      }
      return next;
    });
  }

  function togglePageSelection(): void {
    if (!pageUsers.length) return;

    setSelectedIds((current) => {
      const next = new Set(current);

      if (allPageSelected) {
        pageUsers.forEach((user) => next.delete(user.id));
        setStatus(
          'Current page selection cleared. ' +
          userCountText(next.size, 'selected')
        );
      } else {
        pageUsers.forEach((user) => next.add(user.id));
        setStatus(
          'Current page selected. ' +
          userCountText(next.size, 'selected')
        );
      }

      return next;
    });
  }

  function clearSelection(): void {
    setSelectedIds(new Set<number>());
    setStatus('Selection cleared. 0 users selected.');
  }

  const resultSummary = userCountText(filteredUsers.length, 'found');
  const selectionSummary = userCountText(selectedIds.size, 'selected');
  const sortIndicator = (key: SortKey): string =>
    sortKey === key ? (sortDirection === 'asc' ? ' ↑' : ' ↓') : '';

  return (
    <main className="main">
      <section className="card" aria-labelledby="directory-title">
        <header className="header">
          <div>
            <h1 id="directory-title">User directory</h1>
            <p className="subtitle">
              Search, sort, paginate, and select users without losing context.
            </p>
          </div>
          <p className="selection-summary" id="selection-summary">
            {selectionSummary}
          </p>
        </header>

        <div className="toolbar">
          <label className="search-field">
            <span>Search users</span>
            <input
              className="search-input"
              type="search"
              value={query}
              onChange={handleSearchChange}
              onKeyDown={handleSearchKeyDown}
              aria-label="Search users"
              aria-describedby="result-summary"
              placeholder="Name, email, or role"
            />
          </label>

          <label className="page-size-field">
            <span>Rows per page</span>
            <select
              className="page-size"
              value={pageSize}
              onChange={handlePageSizeChange}
              aria-label="Rows per page"
            >
              {PAGE_SIZES.map((size) => (
                <option value={size} key={size}>
                  {size}
                </option>
              ))}
            </select>
          </label>

          <button
            type="button"
            className="clear-selection"
            onClick={clearSelection}
            disabled={selectedIds.size === 0}
            aria-label="Clear selected users"
          >
            Clear selection
          </button>
        </div>

        <div className="summary-row">
          <p className="result-summary" id="result-summary">
            {resultSummary}
          </p>
        </div>

        <div className="table-scroll">
          <table className="table">
            <caption>User directory</caption>
            <thead>
              <tr>
                <th className="select-header" scope="col">
                  <input
                    ref={selectPageRef}
                    className="select-page"
                    type="checkbox"
                    checked={allPageSelected}
                    onChange={togglePageSelection}
                    disabled={pageUsers.length === 0}
                    aria-label="Select all users on this page"
                    aria-checked={pageSelectionState}
                  />
                  <span className="visually-hidden">Select</span>
                </th>
                <th
                  className="id-header"
                  scope="col"
                  aria-sort={
                    sortKey === 'id'
                      ? sortDirection === 'asc'
                        ? 'ascending'
                        : 'descending'
                      : undefined
                  }
                >
                  <button
                    type="button"
                    className="sort-button sort-id"
                    onClick={() => handleSort('id')}
                    aria-label="Sort by ID"
                  >
                    ID{sortIndicator('id')}
                  </button>
                </th>
                <th
                  className="name-header"
                  scope="col"
                  aria-sort={
                    sortKey === 'name'
                      ? sortDirection === 'asc'
                        ? 'ascending'
                        : 'descending'
                      : undefined
                  }
                >
                  <button
                    type="button"
                    className="sort-button sort-name"
                    onClick={() => handleSort('name')}
                    aria-label="Sort by Name"
                  >
                    Name{sortIndicator('name')}
                  </button>
                </th>
                <th scope="col">Email</th>
                <th
                  className="role-header"
                  scope="col"
                  aria-sort={
                    sortKey === 'role'
                      ? sortDirection === 'asc'
                        ? 'ascending'
                        : 'descending'
                      : undefined
                  }
                >
                  <button
                    type="button"
                    className="sort-button sort-role"
                    onClick={() => handleSort('role')}
                    aria-label="Sort by Role"
                  >
                    Role{sortIndicator('role')}
                  </button>
                </th>
              </tr>
            </thead>
            <tbody>
              {pageUsers.map((user) => (
                <tr
                  className="data-row"
                  data-user-id={user.id}
                  key={user.id}
                >
                  <td>
                    <input
                      className="row-select"
                      type="checkbox"
                      checked={selectedIds.has(user.id)}
                      onChange={() => toggleUser(user)}
                      aria-label={'Select ' + user.name}
                    />
                  </td>
                  <td className="user-id">{user.id}</td>
                  <td className="user-name">{user.name}</td>
                  <td className="user-email">{user.email}</td>
                  <td className="user-role">{user.role}</td>
                </tr>
              ))}
              {pageUsers.length === 0 && (
                <tr className="empty-state">
                  <td colSpan={5}>No users found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <footer
          className="footer"
          role="navigation"
          aria-label="Pagination"
        >
          <button
            type="button"
            className="previous"
            onClick={goPrevious}
            disabled={safeCurrentPage === 1}
          >
            Previous
          </button>
          <span className="page-info">
            Page {safeCurrentPage} of {totalPages}
          </span>
          <button
            type="button"
            className="next"
            onClick={goNext}
            disabled={safeCurrentPage === totalPages}
          >
            Next
          </button>
        </footer>

        <p
          className="table-status"
          role="status"
          aria-live="polite"
          aria-atomic="true"
        >
          {status}
        </p>
      </section>
    </main>
  );
}
